<template>
    <div class="addEdit-block" :style='{"padding":"0"}' style="width: 100%;">
        <el-form
            :style='{"borderRadius":"6px","padding":"30px","margin":"30px"}'
            class="add-update-preview"
            ref="ruleForm"
            :model="ruleForm"
            :rules="rules"
            label-width="120px"
        >
            <el-row>
                <input id="updateId" name="id" type="hidden">
                <el-col :span="12">
                    <el-form-item :style='{"width":"98%","margin":"0 1% 20px","display":"inline-block"}' class="input" v-if="type!='info'" label="课后习题名称" prop="homeworkName">
                        <el-input v-model="ruleForm.homeworkName" placeholder="课后习题名称" clearable :readonly="ro.homeworkName"></el-input>
                    </el-form-item>
                    <el-form-item :style='{"width":"98%","margin":"0 1% 20px","display":"inline-block"}' v-else class="input" label="课后习题名称" prop="homeworkName">
                        <el-input v-model="ruleForm.homeworkName" placeholder="课后习题名称" readonly></el-input>
                    </el-form-item>
                </el-col>
                <el-col :span="12">
                    <el-form-item :style='{"width":"98%","margin":"0 1% 20px","display":"inline-block"}' class="input" v-if="type!='info'" label="课后习题总分数" prop="homeworkMyscore">
                        <el-input v-model="ruleForm.homeworkMyscore" placeholder="课后习题总分数" clearable :readonly="ro.homeworkMyscore"></el-input>
                    </el-form-item>
                    <el-form-item :style='{"width":"98%","margin":"0 1% 20px","display":"inline-block"}' v-else class="input" label="课后习题总分数" prop="homeworkMyscore">
                        <el-input v-model="ruleForm.homeworkMyscore" placeholder="课后习题总分数" readonly></el-input>
                    </el-form-item>
                </el-col>

                <el-col :span="12">
                    <el-form-item :style='{"width":"98%","margin":"0 1% 20px","display":"inline-block"}' class="select" v-if="type!='info'" label="组卷方式" prop="zujuanTypes">
                        <el-select v-model="ruleForm.zujuanTypes" :disabled="ro.zujuanTypes" placeholder="请选择组卷方式">
                            <el-option
                                v-for="(item,index) in zujuanTypesOptions"
                                v-bind:key="item.codeIndex"
                                :label="item.indexName"
                                :value="item.codeIndex">
                            </el-option>
                        </el-select>
                    </el-form-item>
                    <el-form-item :style='{"width":"98%","margin":"0 1% 20px","display":"inline-block"}' v-else class="input" label="组卷方式" prop="zujuanValue">
                        <el-input v-model="ruleForm.zujuanValue" placeholder="组卷方式" readonly></el-input>
                    </el-form-item>
                </el-col>
                <el-col :span="12">
                    <el-form-item :style='{"width":"98%","margin":"0 1% 20px","display":"inline-block"}' class="select" v-if="type!='info'" label="课后习题状态" prop="homeworkTypes">
                        <el-select v-model="ruleForm.homeworkTypes" :disabled="ro.homeworkTypes" placeholder="请选择课后习题状态">
                            <el-option
                                v-for="(item,index) in homeworkTypesOptions"
                                v-bind:key="item.codeIndex"
                                :label="item.indexName"
                                :value="item.codeIndex">
                            </el-option>
                        </el-select>
                    </el-form-item>
                    <el-form-item :style='{"width":"98%","margin":"0 1% 20px","display":"inline-block"}' v-else class="input" label="课后习题状态" prop="homeworkValue">
                        <el-input v-model="ruleForm.homeworkValue" placeholder="课后习题状态" readonly></el-input>
                    </el-form-item>
                </el-col>
                <!-- 关联课程下拉框 -->
                <el-col :span="12">
                    <el-form-item :style='{"width":"98%","margin":"0 1% 20px","display":"inline-block"}' class="select" v-if="type!='info'" label="关联课程" prop="courseId">
                        <el-select v-model="ruleForm.courseId" :disabled="ro.courseId" placeholder="请选择关联课程">
                            <el-option
                                v-for="(course, index) in courseOptions"
                                v-bind:key="course.id"
                                :label="course.coursename"
                                :value="course.id">
                            </el-option>
                        </el-select>
                    </el-form-item>
                    <el-form-item :style='{"width":"98%","margin":"0 1% 20px","display":"inline-block"}' v-else class="input" label="关联课程">
                        <el-input v-model="displayCourseName" placeholder="无关联课程" readonly></el-input>
                    </el-form-item>
                </el-col>
                <!-- 关联视频下拉框 -->
                <el-col :span="12">
                    <el-form-item :style='{"width":"98%","margin":"0 1% 20px","display":"inline-block"}' class="select" v-if="type!='info'" label="关联视频" prop="videoId">
                        <el-select v-model="ruleForm.videoId" :disabled="ro.videoId" placeholder="请选择关联视频">
                            <el-option
                                v-for="(item, index) in videoOptions"
                                v-bind:key="item.id"
                                :label="item.title"
                                :value="item.id">
                            </el-option>
                        </el-select>
                    </el-form-item>
                    <el-form-item :style='{"width":"98%","margin":"0 1% 20px","display":"inline-block"}' v-else class="input" label="关联视频" prop="videoTitle">
                        <el-input v-model="displayVideoTitle" placeholder="无关联视频" readonly></el-input>
                    </el-form-item>
                </el-col>
            </el-row>
            <el-form-item :style='{"padding":"0","margin":"0"}' class="btn">
                <el-button :style='{"border":"none","cursor":"pointer","padding":"0","margin":"0 20px 0 0","outline":"none","color":"#ffffff","borderRadius":"4px","background":"#4299e1","width":"128px","lineHeight":"40px","fontSize":"14px","height":"40px","transition":"background-color 0.2s"}' v-if="type!='info'" type="primary" class="btn-success" @click="onSubmit">提交</el-button>
                <el-button :style='{"border":"1px solid #4299e1","cursor":"pointer","padding":"0","margin":"0","outline":"none","color":"#4299e1","borderRadius":"4px","background":"#ffffff","width":"128px","lineHeight":"40px","fontSize":"14px","height":"40px","transition":"all 0.2s"}' v-if="type!='info'" class="btn-close" @click="back()">取消</el-button>
                <el-button :style='{"border":"1px solid #4299e1","cursor":"pointer","padding":"0","margin":"0","outline":"none","color":"#4299e1","borderRadius":"4px","background":"#ffffff","width":"128px","lineHeight":"40px","fontSize":"14px","height":"40px","transition":"all 0.2s"}' v-if="type=='info'" class="btn-close" @click="back()">返回</el-button>
            </el-form-item>
        </el-form>
    </div>
</template>

<script>
    import styleJs from "../../../utils/style.js";

    export default {
        data() {
            return {
                addEditForm: null,
                id: '',
                type: '',
                sessionTable: "",//登录账户所在表名
                role: "",//权限
                userId: "",//当前登录人的id
                videoOptions: [],// 视频选项列表
                courseOptions: [],// 课程选项列表
                
                ro: {
                    homeworkName: false,
                    homeworkDate: false,
                    homeworkMyscore: true,
                    kemuTypes: false,
                    homeworkTypes: false,
                    zujuanTypes: false,
                    homeworkDelete: false,            
                    videoId: false,    // 视频编辑权限控制
                    courseId: false   // 课程编辑权限控制
                },
                ruleForm: {
                    homeworkName: '',
                    homeworkDate: '',
                    homeworkMyscore: 0.0,
                    kemuTypes: '',
                    homeworkTypes: '',
                    zujuanTypes: '',
                    homeworkDelete: '',
                    videoId: '',       // 存储选中的视频ID
                    videoTitle: '',     // 详情页显示视频标题
                    courseId: '',      // 新增：存储选中的课程ID
                    courseName: ''     // 新增：详情页显示课程名称
                },
                kemuTypesOptions: [],
                homeworkTypesOptions: [],
                zujuanTypesOptions: [],
                rules: {
                    homeworkName: [
                        {required: true, message: '课后习题名称不能为空', trigger: 'blur'},
                    ],
                    homeworkMyscore: [
                        {required: true, message: '课后习题总分数不能为空', trigger: 'blur'},
                        {
                            pattern: /^[0-9]*$/,
                            message: '只允许输入整数',
                            trigger: 'blur'
                        }
                    ],
                    homeworkTypes: [
                        {required: true, message: '课后习题状态不能为空', trigger: 'blur'},
                        {
                            pattern: /^[0-9]*$/,
                            message: '只允许输入整数',
                            trigger: 'blur'
                        }
                    ],
                    zujuanTypes: [
                        {required: true, message: '组卷方式不能为空', trigger: 'blur'},
                        {
                            pattern: /^[0-9]*$/,
                            message: '只允许输入整数',
                            trigger: 'blur'
                        }
                    ],
                    homeworkDelete: [
                        {required: true, message: '逻辑删除（1代表未删除 2代表已删除）不能为空', trigger: 'blur'},
                        {
                            pattern: /^[0-9]*$/,
                            message: '只允许输入整数',
                            trigger: 'blur'
                        }
                    ],
                }
            };
        },
        props: ["parent"],
        computed: {
            displayVideoTitle() {
                // 如果有直接存储的标题，优先使用
                if (this.ruleForm.videoTitle) {
                    return this.ruleForm.videoTitle;
                }
                
                // 如果有视频ID但没有标题，从视频选项中查找
                if (this.ruleForm.videoId && this.videoOptions.length > 0) {
                    const selectedVideo = this.videoOptions.find(v => v.id === this.ruleForm.videoId);
                    if (selectedVideo) {
                        return selectedVideo.title;
                    }
                }
                
                // 无关联视频时显示默认文本
                return "无关联视频";
            },
            // 课程名称显示计算属性
            displayCourseName() {
                // 如果有直接存储的课程名称，优先使用
                if (this.ruleForm.courseName) {
                    return this.ruleForm.courseName;
                }
                
                // 如果有课程ID但没有名称，从课程选项中查找
                if (this.ruleForm.courseId && this.courseOptions.length > 0) {
                    const selectedCourse = this.courseOptions.find(c => c.id === this.ruleForm.courseId);
                    if (selectedCourse) {
                        return selectedCourse.coursename;
                    }
                }
                
                // 无关联课程时显示默认文本
                return "无关联课程";
            }
        },
        created() {
            //获取当前登录用户的信息
            this.sessionTable = this.$storage.get("sessionTable");
            this.role = this.$storage.get("role");
            this.userId = this.$storage.get("userId");


            if (this.role != "管理员") {
            }
            this.addEditForm = styleJs.addStyle();

            this.addEditUploadStyleChange()
            //获取下拉框信息

            this.$http({
                url: `dictionary/page?page=1&limit=100&sort=&order=&dicCode=homework_types`,
                method: "get"
            }).then(({data}) => {
                if (data && data.code === 0) {
                    this.homeworkTypesOptions = data.data.list;
                }
            });
            this.$http({
                url: `dictionary/page?page=1&limit=100&sort=&order=&dicCode=zujuan_types`,
                method: "get"
            }).then(({data}) => {
                if (data && data.code === 0) {
                    this.zujuanTypesOptions = data.data.list;
                }
            });

            // 加载视频选项
            this.loadVideoOptions();
            // 加载课程选项
            this.loadCourseOptions();

        },
        mounted() {
        },
        methods: {
            // 加载课程选项
            loadCourseOptions() {
                this.$http({
                    url: `course/page?page=1&limit=1000`, // 获取所有课程
                    method: "get"
                }).then(({data}) => {
                    if (data && data.code === 0) {
                        this.courseOptions = data.data.list || [];
                        // 如果已加载详情数据，更新课程名称
                        if (this.id && (this.type === 'info' || this.type === 'else')) {
                            this.updateCourseName();
                        }
                    }
                }).catch(error => {
                    console.error('加载课程列表失败:', error);
                    this.$message.error('加载课程列表失败，请刷新页面重试');
                });
            },
            
            // 更新课程名称
            updateCourseName() {
                if (this.ruleForm.courseId && this.courseOptions.length > 0) {
                    const selectedCourse = this.courseOptions.find(c => c.id === this.ruleForm.courseId);
                    if (selectedCourse) {
                        this.ruleForm.courseName = selectedCourse.coursename;
                    } else {
                        this.ruleForm.courseName = "课程不存在或已删除";
                    }
                } else {
                    this.ruleForm.courseName = "";
                }
            },
            // 加载视频选项
            loadVideoOptions() {
                this.$http({
                    url: `course/page?page=1&limit=1000`, // 获取所有课程
                    method: "get"
                }).then(({data}) => {
                    if (data && data.code === 0) {
                        const allVideos = [];
                        // 遍历所有课程，提取视频信息
                        data.data.list.forEach(course => {
                            if (course.video) {
                                try {
                                    // 解析video字段的JSON数组
                                    const videos = JSON.parse(course.video);
                                    if (Array.isArray(videos)) {
                                        // 添加课程名称前缀，便于区分
                                        videos.forEach(video => {
                                            allVideos.push({
                                                id: video.id,
                                                title: `${course.coursename} - ${video.title}`,
                                                url: video.url
                                            });
                                        });

                                    }
                                } catch (e) {
                                    console.error('解析视频数据失败:', e);
                                }
                            }
                        });
                        // 去重处理
                        const uniqueVideos = Array.from(new Map(allVideos.map(v => [v.id, v])).values());
                        this.videoOptions = uniqueVideos;
                        // 如果已加载详情数据，重新关联视频标题
                        if (this.id && (this.type === 'info' || this.type === 'else')) {
                            this.updateVideoTitle();
                        }
                        // 如果课程选项已加载，更新课程名称
                        if (this.courseOptions.length > 0) {
                            this.updateCourseName();
                        }
                    }
                });
            },
             // 单独的视频标题更新方法
             updateVideoTitle() {
                if (this.ruleForm.videoId && this.videoOptions.length > 0) {
                    const selectedVideo = this.videoOptions.find(v => v.id === this.ruleForm.videoId);
                    if (selectedVideo) {
                        this.ruleForm.videoTitle = selectedVideo.title;
                    } else {
                        this.ruleForm.videoTitle = "视频不存在或已删除";
                    }
                } else {
                    this.ruleForm.videoTitle = "";
                }
            },
            // 下载
            download(file) {
                window.open(" ${file} ")
            },
            // 初始化
            init(id, type) {
                if (id) {
                    this.id = id;
                    this.type = type;
                }
                if (this.type == 'info' || this.type == 'else') {
                    this.info(id);
                }
                // 获取用户信息
                this.$http({
                    url: `${this.$storage.get("sessionTable")}/session`,
                    method: "get"
                }).then(({data}) => {
                    if (data && data.code === 0) {
                        var json = data.data;
                    } else {
                        this.$message.error(data.msg);
                    }
                });
            },
            // 多级联动参数
            info(id) {
                let _this = this;
                _this.$http({
                    url: `homework/info/${id}`,
                    method: 'get'
                }).then(({data}) => {
                    if (data && data.code === 0) {
                        _this.ruleForm = data.data;
                        // 处理视频信息，显示视频标题
                        if (_this.ruleForm.videoId && _this.videoOptions.length > 0) {
                            const selectedVideo = _this.videoOptions.find(v => v.id === _this.ruleForm.videoId);
                            if (selectedVideo) {
                                _this.ruleForm.videoTitle = selectedVideo.title;
                            }
                        }
                        // 确保时间格式正确，如果后端返回的是时间戳需要转换
                        if (typeof _this.ruleForm.startTime === 'number') {
                            _this.ruleForm.startTime = new Date(_this.ruleForm.startTime).toISOString().slice(0, 19).replace('T', ' ');
                        }
                        if (typeof _this.ruleForm.endTime === 'number') {
                            _this.ruleForm.endTime = new Date(_this.ruleForm.endTime).toISOString().slice(0, 19).replace('T', ' ');
                        }
                        // 视频选项可能还未加载完成，使用$nextTick确保DOM更新后执行
                        this.$nextTick(() => {
                            // 如果视频选项已加载，直接更新标题
                            if (this.videoOptions.length > 0) {
                                this.updateVideoTitle();
                            }
                        });
                    } else {
                        _this.$message.error(data.msg);
                    }
                });
            },
            // 提交
            onSubmit() {
                this.$refs["ruleForm"].validate(valid => {
                    if (valid) {
                        this.$http({
                            url: `homework/${!this.ruleForm.id ? "save" : "update"}`,
                            method: "post",
                            data: this.ruleForm
                        }).then(({data}) => {
                            if (data && data.code === 0) {
                                this.$message({
                                    message: "操作成功",
                                    type: "success",
                                    duration: 1500,
                                    onClose: () => {
                                        this.parent.showFlag = true;
                                        this.parent.addOrUpdateFlag = false;
                                        this.parent.homeworkCrossAddOrUpdateFlag = false;
                                        this.parent.search();
                                        this.parent.contentStyleChange();
                                    }
                                });
                            } else {
                                this.$message.error(data.msg);
                            }
                        });
                    }
                });
            },
            // 获取uuid
            getUUID() {
                return new Date().getTime();
            },
            // 返回
            back() {
                this.parent.showFlag = true;
                this.parent.addOrUpdateFlag = false;
                this.parent.homeworkCrossAddOrUpdateFlag = false;
                this.parent.contentStyleChange();
            },
            //图片
            addEditUploadStyleChange() {
                this.$nextTick(() => {
                    document.querySelectorAll('.addEdit-block .upload .el-upload-list--picture-card .el-upload-list__item').forEach(el => {
                        el.style.width = this.addEditForm.uploadHeight
                        el.style.height = this.addEditForm.uploadHeight
                        el.style.borderWidth = this.addEditForm.uploadBorderWidth
                        el.style.borderStyle = this.addEditForm.uploadBorderStyle
                        el.style.borderColor = this.addEditForm.uploadBorderColor
                        el.style.borderRadius = this.addEditForm.uploadBorderRadius
                        el.style.backgroundColor = this.addEditForm.uploadBgColor
                    })
                })
            },
        }
    };
</script>

