<template>
	<div class="addEdit-block" :style='{"padding":"0"}' style="width: 100%;">
		<el-form
			:style='{"borderRadius":"6px","padding":"30px","margin":"30px"}'
			class="add-update-preview"
			ref="ruleForm"
			:model="ruleForm"
			:rules="rules"
			label-width="120px"
		>
			<template >
				
				<el-form-item :style='{"width":"48%","margin":"0 0.5% 20px","display":"inline-block"}' class="input" v-if="type!='info'" label="资料编号" prop="resourcenumber">
					<el-input v-model="ruleForm.resourcenumber" placeholder="资料编号" readonly></el-input>
				</el-form-item>
				<el-form-item :style='{"width":"48%","margin":"0 0.5% 20px","display":"inline-block"}' class="input" v-else-if="ruleForm.resourcenumber" label="资料编号" prop="resourcenumber">
					<el-input v-model="ruleForm.resourcenumber" placeholder="资料编号" readonly></el-input>
				</el-form-item>
				<el-form-item :style='{"width":"48%","margin":"0 0.5% 20px","display":"inline-block"}' class="input" v-if="type!='info'"  label="资料名称" prop="resourcename">
					<el-input v-model="ruleForm.resourcename" placeholder="资料名称" clearable  :readonly="ro.resourcename"></el-input>
				</el-form-item>
				<el-form-item :style='{"width":"48%","margin":"0 0.5% 20px","display":"inline-block"}' v-else class="input" label="资料名称" prop="resourcename">
					<el-input v-model="ruleForm.resourcename" placeholder="资料名称" readonly></el-input>
				</el-form-item>
				<el-form-item :style='{"width":"48%","margin":"0 0.5% 20px","display":"inline-block"}' class="select" v-if="type!='info'"  label="资料类别" prop="resourcesort">
					<el-select :disabled="ro.resourcesort" v-model="ruleForm.resourcesort" placeholder="请选择资料类别" >
						<el-option
							v-for="(item,index) in resourcesortOptions"
							v-bind:key="index"
							:label="item"
							:value="item">
						</el-option>
					</el-select>
				</el-form-item>
				<el-form-item :style='{"width":"48%","margin":"0 0.5% 20px","display":"inline-block"}' v-else class="input" label="资料类别" prop="resourcesort">
					<el-input v-model="ruleForm.resourcesort"
						placeholder="资料类别" readonly></el-input>
				</el-form-item>
				<el-form-item :style='{"width":"48%","margin":"0 0.5% 20px","display":"inline-block"}' class="upload" v-if="type!='info' && !ro.cover" label="封面" prop="cover">
					<file-upload
						tip="点击上传封面"
						action="file/upload"
						:limit="3"
						:multiple="true"
						:fileUrls="ruleForm.cover?ruleForm.cover:''"
						@change="coverUploadChange"
					></file-upload>
				</el-form-item>
				<el-form-item :style='{"width":"48%","margin":"0 0.5% 20px","display":"inline-block"}' class="upload" v-else-if="ruleForm.cover" label="封面" prop="cover">
					<img v-if="ruleForm.cover.substring(0,4)=='http'" class="upload-img" style="margin-right:20px;" v-bind:key="index" :src="ruleForm.cover.split(',')[0]" width="100" height="100">
					<img v-else class="upload-img" style="margin-right:20px;" v-bind:key="item" v-for="(item,index) in ruleForm.cover.split(',')" :src="$base.url+item" width="100" height="100">
				</el-form-item>
				
			</template>
				<el-form-item :style='{"width":"48%","margin":"0 0.5% 20px","display":"inline-block"}' class="textarea" v-if="type!='info'" label="资料简介" prop="resourceintroduction">
					<el-input
					  style="min-width: 200px; max-width: 600px;"
					  type="textarea"
					  :rows="8"
					  placeholder="资料简介"
					  v-model="ruleForm.resourceintroduction" >
					</el-input>
				</el-form-item>
				<el-form-item :style='{"width":"48%","margin":"0 0.5% 20px","display":"inline-block"}' v-else-if="ruleForm.resourceintroduction" label="资料简介" prop="resourceintroduction">
					<span :style='{"fontSize":"14px","lineHeight":"40px","color":"#777","fontWeight":"500","display":"inline-block"}'>{{ruleForm.resourceintroduction}}</span>
				</el-form-item>
				<el-form-item :style='{"width":"48%","margin":"0 0.5% 20px","display":"inline-block"}' v-if="type!='info'"  label="资料详情" prop="resourcedetail">
					<editor 
						style="min-width: 200px; max-width: 600px;"
						v-model="ruleForm.resourcedetail" 
						class="editor" 
						action="file/upload">
					</editor>
				</el-form-item>
				<el-form-item :style='{"width":"48%","margin":"0 0.5% 20px","display":"inline-block"}' v-else-if="ruleForm.resourcedetail" label="资料详情" prop="resourcedetail">
                    <span :style='{"fontSize":"14px","lineHeight":"40px","color":"#777","fontWeight":"500","display":"inline-block"}' v-html="ruleForm.resourcedetail"></span>
                </el-form-item>
			<el-form-item :style='{"padding":"0","margin":"0"}' class="btn">
				<el-button :style='{"border":"none","cursor":"pointer","padding":"0","margin":"0 20px 0 0","outline":"none","color":"#ffffff","borderRadius":"4px","background":"#4299e1","width":"128px","lineHeight":"40px","fontSize":"14px","height":"40px","transition":"background-color 0.2s"}'  v-if="type!='info'" type="primary" class="btn-success" @click="onSubmit">提交</el-button>
				<el-button :style='{"border":"1px solid #4299e1","cursor":"pointer","padding":"0","margin":"0","outline":"none","color":"#4299e1","borderRadius":"4px","background":"#ffffff","width":"128px","lineHeight":"40px","fontSize":"14px","height":"40px","transition":"all 0.2s"}' v-if="type!='info'" class="btn-close" @click="back()">取消</el-button>
				<el-button :style='{"border":"1px solid #4299e1","cursor":"pointer","padding":"0","margin":"0","outline":"none","color":"#4299e1","borderRadius":"4px","background":"#ffffff","width":"128px","lineHeight":"40px","fontSize":"14px","height":"40px","transition":"all 0.2s"}' v-if="type=='info'" class="btn-close" @click="back()">返回</el-button>
			</el-form-item>
		</el-form>
    

  </div>
</template>
<script>
// 数字，邮件，手机，url，身份证校验
import { isNumber,isIntNumer,isEmail,isPhone, isMobile,isURL,checkIdCard } from "@/utils/validate";
export default {
	data() {
		let self = this
		var validateIdCard = (rule, value, callback) => {
			if(!value){
				callback();
			} else if (!checkIdCard(value)) {
				callback(new Error("请输入正确的身份证号码"));
			} else {
				callback();
			}
		};
		var validateUrl = (rule, value, callback) => {
			if(!value){
				callback();
			} else if (!isURL(value)) {
				callback(new Error("请输入正确的URL地址"));
			} else {
				callback();
			}
		};
		var validateMobile = (rule, value, callback) => {
			if(!value){
				callback();
			} else if (!isMobile(value)) {
				callback(new Error("请输入正确的手机号码"));
			} else {
				callback();
			}
		};
		var validatePhone = (rule, value, callback) => {
			if(!value){
				callback();
			} else if (!isPhone(value)) {
				callback(new Error("请输入正确的电话号码"));
			} else {
				callback();
			}
		};
		var validateEmail = (rule, value, callback) => {
			if(!value){
				callback();
			} else if (!isEmail(value)) {
				callback(new Error("请输入正确的邮箱地址"));
			} else {
				callback();
			}
		};
		var validateNumber = (rule, value, callback) => {
			if(!value){
				callback();
			} else if (!isNumber(value)) {
				callback(new Error("请输入数字"));
			} else {
				callback();
			}
		};
		var validateIntNumber = (rule, value, callback) => {
			if(!value){
				callback();
			} else if (!isIntNumer(value)) {
				callback(new Error("请输入整数"));
			} else {
				callback();
			}
		};
		return {
			id: '',
			type: '',
			
			
			ro:{
				level : false,
				resourcenumber : false,
				resourcename : false,
				resourcesort : false,
				cover : false,
				anlishizhang : false,
				resourceintroduction : false,
				resourcedetail : false,
				teacheraccount : false,
				teachername : false,
			},
			
			
			ruleForm: {
				level: '',
				resourcenumber: this.getUUID(),
				resourcename: '',
				resourcesort: '',
				cover: '',
				anlishizhang: '',
				resourceintroduction: '',
				resourcedetail: '',
				teacheraccount: '',
				teachername: '',
			},
		
			resourcesortOptions: [],
			
			rules: {
				level: [
				],
				resourcenumber: [
				],
				resourcename: [
				],
				resourcesort: [
				],
				cover: [
				],
				anlishizhang: [
				],
				resourceintroduction: [
				],
				resourcedetail: [
				],
				teacheraccount: [
				],
				teachername: [
				],
			}
		};
	},
	props: ["parent"],
	computed: {



	},
    components: {
    },
	created() {
	},
	methods: {
		
		// 下载
		download(file){
			window.open(`${file}`)
		},
		// 初始化
		init(id,type) {
			if (id) {
				this.id = id;
				this.type = type;
			}
			if(this.type=='info'||this.type=='else'){
				this.info(id);
			}else if(this.type=='logistics'){
				this.logistics=false;
				this.info(id);
			}else if(this.type=='cross'){
				var obj = this.$storage.getObj('crossObj');
				for (var o in obj){
						if(o=='level'){
							this.ruleForm.level = obj[o];
							this.ro.level = true;
							continue;
						}
						if(o=='resourcenumber'){
							this.ruleForm.resourcenumber = obj[o];
							this.ro.resourcenumber = true;
							continue;
						}
						if(o=='resourcename'){
							this.ruleForm.resourcename = obj[o];
							this.ro.resourcename = true;
							continue;
						}
						if(o=='resourcesort'){
							this.ruleForm.resourcesort = obj[o];
							this.ro.resourcesort = true;
							continue;
						}
						if(o=='cover'){
							this.ruleForm.cover = obj[o];
							this.ro.cover = true;
							continue;
						}
						if(o=='anlishizhang'){
							this.ruleForm.anlishizhang = obj[o];
							this.ro.anlishizhang = true;
							continue;
						}
						if(o=='resourceintroduction'){
							this.ruleForm.resourceintroduction = obj[o];
							this.ro.resourceintroduction = true;
							continue;
						}
						if(o=='resourcedetail'){
							this.ruleForm.resourcedetail = obj[o];
							this.ro.resourcedetail = true;
							continue;
						}
						if(o=='teacheraccount'){
							this.ruleForm.teacheraccount = obj[o];
							this.ro.teacheraccount = true;
							continue;
						}
						if(o=='teachername'){
							this.ruleForm.teachername = obj[o];
							this.ro.teachername = true;
							continue;
						}
				}
				










			}
			
			
			// 获取用户信息
			this.$http({
				url: `${this.$storage.get('sessionTable')}/session`,
				method: "get"
			}).then(({ data }) => {
				if (data && data.code === 0) {
					
					var json = data.data;
					if(((json.level!=''&&json.level) || json.level==0) && this.$storage.get("role")!="管理员"){
						this.ruleForm.level = json.level
						this.ro.level = true;
					}
					if(((json.teacheraccount!=''&&json.teacheraccount) || json.teacheraccount==0) && this.$storage.get("role")!="管理员"){
						this.ruleForm.teacheraccount = json.teacheraccount
						this.ro.teacheraccount = true;
					}
					if(((json.teachername!=''&&json.teachername) || json.teachername==0) && this.$storage.get("role")!="管理员"){
						this.ruleForm.teachername = json.teachername
						this.ro.teachername = true;
					}
				} else {
					this.$message.error(data.msg);
				}
			});
			
            this.$http({
				url: `option/resourcesort/resourcesort`,
				method: "get"
            }).then(({ data }) => {
				if (data && data.code === 0) {
					this.resourcesortOptions = data.data;
				} else {
					this.$message.error(data.msg);
				}
            });
			
		},
    // 多级联动参数

    info(id) {
      this.$http({
        url: `resource/info/${id}`,
        method: "get"
      }).then(({ data }) => {
        if (data && data.code === 0) {
        this.ruleForm = data.data;
        //解决前台上传图片后台不显示的问题
        let reg=new RegExp('../../../upload','g')//g代表全部
        this.ruleForm.resourcedetail = this.ruleForm.resourcedetail.replace(reg,'../../../onlinecourseteachsys/upload');
        } else {
          this.$message.error(data.msg);
        }
      });
    },


    // 提交
    onSubmit() {










	if(this.ruleForm.cover!=null) {
		this.ruleForm.cover = this.ruleForm.cover.replace(new RegExp(this.$base.url,"g"),"");
	}











var objcross = this.$storage.getObj('crossObj');

      //更新跨表属性
       var crossuserid;
       var crossrefid;
       var crossoptnum;
       if(this.type=='cross'){
                var statusColumnName = this.$storage.get('statusColumnName');
                var statusColumnValue = this.$storage.get('statusColumnValue');
                if(statusColumnName!='') {
                        var obj = this.$storage.getObj('crossObj');
                       if(statusColumnName && !statusColumnName.startsWith("[")) {
                               for (var o in obj){
                                 if(o==statusColumnName){
                                   obj[o] = statusColumnValue;
                                 }
                               }
                               var table = this.$storage.get('crossTable');
                             this.$http({
                                 url: `${table}/update`,
                                 method: "post",
                                 data: obj
                               }).then(({ data }) => {});
                       } else {
                               crossuserid=this.$storage.get('userid');
                               crossrefid=obj['id'];
                               crossoptnum=this.$storage.get('statusColumnName');
                               crossoptnum=crossoptnum.replace(/\[/,"").replace(/\]/,"");
                        }
                }
        }
       this.$refs["ruleForm"].validate(valid => {
         if (valid) {
		 if(crossrefid && crossuserid) {
			 this.ruleForm.crossuserid = crossuserid;
			 this.ruleForm.crossrefid = crossrefid;
			let params = { 
				page: 1, 
				limit: 10, 
				crossuserid:this.ruleForm.crossuserid,
				crossrefid:this.ruleForm.crossrefid,
			} 
			this.$http({ 
				url: "resource/page", 
				method: "get", 
				params: params 
			}).then(({ 
				data 
			}) => { 
				if (data && data.code === 0) { 
				       if(data.data.total>=crossoptnum) {
					     this.$message.error(this.$storage.get('tips'));
					       return false;
				       } else {
					 this.$http({
					   url: `resource/${!this.ruleForm.id ? "save" : "update"}`,
					   method: "post",
					   data: this.ruleForm
					 }).then(({ data }) => {
					   if (data && data.code === 0) {
					     this.$message({
					       message: "操作成功",
					       type: "success",
					       duration: 1500,
					       onClose: () => {
						 this.parent.showFlag = true;
						 this.parent.addOrUpdateFlag = false;
						 this.parent.resourceCrossAddOrUpdateFlag = false;
						 this.parent.search();
						 this.parent.contentStyleChange();
					       }
					     });
					   } else {
					     this.$message.error(data.msg);
					   }
					 });

				       }
				} else { 
				} 
			});
		 } else {
			 this.$http({
			   url: `resource/${!this.ruleForm.id ? "save" : "update"}`,
			   method: "post",
			   data: this.ruleForm
			 }).then(({ data }) => {
			   if (data && data.code === 0) {
			     this.$message({
			       message: "操作成功",
			       type: "success",
			       duration: 1500,
			       onClose: () => {
				 this.parent.showFlag = true;
				 this.parent.addOrUpdateFlag = false;
				 this.parent.resourceCrossAddOrUpdateFlag = false;
				 this.parent.search();
				 this.parent.contentStyleChange();
			       }
			     });
			   } else {
			     this.$message.error(data.msg);
			   }
			 });
		 }
         }
       });
    },
    // 获取uuid
    getUUID () {
      return new Date().getTime();
    },
    // 返回
    back() {
      this.parent.showFlag = true;
      this.parent.addOrUpdateFlag = false;
      this.parent.resourceCrossAddOrUpdateFlag = false;
      this.parent.contentStyleChange();
    },
    coverUploadChange(fileUrls) {
	    this.ruleForm.cover = fileUrls;
    },
  }
};
</script>
